parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "professional": {
      "type": "string",
      "description": "Professional tone rewrite — formal and polished"
    },
    "casual": {
      "type": "string",
      "description": "Casual tone rewrite — warm and conversational"
    },
    "persuasive": {
      "type": "string",
      "description": "Persuasive tone rewrite — compelling and action-oriented"
    },
    "concise": {
      "type": "string",
      "description": "Concise tone rewrite — stripped to minimum words"
    },
    "empathetic": {
      "type": "string",
      "description": "Empathetic tone rewrite — warm and understanding"
    }
  },
  "required": ["professional", "casual", "persuasive", "concise", "empathetic"]
}

parameters.jsCode:
// Combine AI output with form config data
const aiOutput = $input.first().json.output;
const config = $('2. Set — Config Values').item.json;

const professional = aiOutput.professional || 'Could not generate professional version.';
const casual = aiOutput.casual || 'Could not generate casual version.';
const persuasive = aiOutput.persuasive || 'Could not generate persuasive version.';
const concise = aiOutput.concise || 'Could not generate concise version.';
const empathetic = aiOutput.empathetic || 'Could not generate empathetic version.';

// Build the full Google Doc content
const docContent = `AI TONE REWRITER RESULTS

Project: ${config.projectName}
Content Type: ${config.contentType}
Target Audience: ${config.targetAudience}
Generated: ${config.runDate}
Powered by: ${config.companyName} + GPT-4o-mini

${'='.repeat(60)}

ORIGINAL TEXT:

${config.originalText}

${'='.repeat(60)}

VERSION 1 — PROFESSIONAL

${professional}

${'='.repeat(60)}

VERSION 2 — CASUAL AND FRIENDLY

${casual}

${'='.repeat(60)}

VERSION 3 — PERSUASIVE

${persuasive}

${'='.repeat(60)}

VERSION 4 — CONCISE

${concise}

${'='.repeat(60)}

VERSION 5 — EMPATHETIC

${empathetic}

${'='.repeat(60)}

All 5 versions generated automatically by n8n + GPT-4o-mini`;

// Build Slack preview (show concise version as quick preview)
const slackPreview = `*New Tone Rewrite Ready*

*Project:* ${config.projectName}
*Content Type:* ${config.contentType}
*Generated:* ${config.runDate}

*Quick Preview — Concise Version:*
${concise}

_5 versions saved to Google Drive_`;

return [{
  json: {
    docContent,
    docTitle: config.docTitle,
    folderId: config.folderId,
    slackChannel: config.slackChannel,
    slackPreview,
    professional,
    casual,
    persuasive,
    concise,
    empathetic,
    projectName: config.projectName
  }
}];

// Convert doc content text to binary for Google Drive upload
const item = $input.first().json;

// Convert text content to base64 encoded binary
const textContent = item.docContent || '';
const base64Content = Buffer.from(textContent, 'utf-8').toString('base64');

return [{
  json: {
    docTitle: item.docTitle,
    folderId: item.folderId,
    slackChannel: item.slackChannel,
    slackPreview: item.slackPreview,
    projectName: item.projectName
  },
  binary: {
    data: {
      data: base64Content,
      mimeType: 'text/plain',
      fileName: item.docTitle + '.txt',
      fileExtension: 'txt'
    }
  }
}];
